#include <bits/stdc++.h>
using namespace std;

int dx[8]={0,1,1,1,0,-1,-1,-1};
int dy[8]={1,1,0,-1,-1,-1,0,1};

int bz[105][105],num=0;
int h[10005][3];

int m,n;

void bfs(int p,int q)
{
	int x,y,t,w,i;

	num++;
	bz[p][q]=0;

	t=0;
	w=1;

	h[0][1]=p;
	h[0][2]=q; 

	 do{

    for(i=0; i<=7; i++ )
		{
		   x=h[t][1]+dx[i];
		   y=h[t][2]+dy[i];
		   if(x>=0&&x<=m-1&&y>=0&&y<=n-1&&bz[x][y])
		   {

		   h[w][1]=x;
		   h[w][2]=y;
		   bz[x][y]=0;
		   w++;
		   }
	    }
	    t++;
		}while(t<w);

		return;


}



int main() 
{ 
 int i,j;
 char s[105],ch;
 scanf("%d%d",&m,&n);

 for(i=0;i<=m-1;i++)
   for(j=0;j<=n-1;j++)
     bz[i][j]=1;

//memset(bz,1,sizeof(bz)); //memory set

   for(i=0;i<=m-1;i++)
   {
   	 scanf("%s",s);
   	 for(j=0;j<=n-1;j++)
   	 if(s[j]=='.') bz[i][j]=0;
   }  

   for(i=0;i<=m-1;i++)
   for(j=0;j<=n-1;j++)
    if(bz[i][j])
    bfs(i,j);


  printf("%d",num);     
  return 0; 
}
